class TransactionProcessor {
    static let shared = TransactionProcessor()
    private init() {}
    
    private let secureStorage = SecureStorage.shared
    private let queue = DispatchQueue(label: "com.bankingapp.transactions", attributes: .concurrent)
    
    func processTransaction(transaction: Transaction, completion: @escaping (Bool, String?) -> Void) {
        queue.async(flags: .barrier) {
            guard SecurityManager.shared.checkIntegrity() else {
                DispatchQueue.main.async {
                    completion(false, "Security check failed")
                }
                return
            }
            
            guard var fromAccount = self.secureStorage.loadAccount(accountNumber: transaction.fromAccount) else {
                DispatchQueue.main.async {
                    completion(false, "Source account not found")
                }
                return
            }
            
            if transaction.type == .debit || transaction.type == .transfer {
                guard fromAccount.balance >= transaction.amount else {
                    DispatchQueue.main.async {
                        completion(false, "Insufficient funds")
                    }
                    return
                }
                fromAccount.balance -= transaction.amount
            } else {
                fromAccount.balance += transaction.amount
            }
            
            fromAccount.transactions.append(transaction)
            
            guard self.secureStorage.saveAccount(fromAccount) else {
                DispatchQueue.main.async {
                    completion(false, "Failed to save transaction")
                }
                return
            }
            
            if transaction.type == .transfer {
                guard var toAccount = self.secureStorage.loadAccount(accountNumber: transaction.toAccount) else {
                    DispatchQueue.main.async {
                        completion(false, "Destination account not found")
                    }
                    return
                }
                
                toAccount.balance += transaction.amount
                let creditTransaction = Transaction(
                    id: UUID().uuidString,
                    amount: transaction.amount,
                    type: .credit,
                    timestamp: transaction.timestamp,
                    description: transaction.description,
                    fromAccount: transaction.fromAccount,
                    toAccount: transaction.toAccount
                )
                toAccount.transactions.append(creditTransaction)
                
                guard self.secureStorage.saveAccount(toAccount) else {
                    DispatchQueue.main.async {
                        completion(false, "Failed to update destination account")
                    }
                    return
                }
            }
            
            DispatchQueue.main.async {
                completion(true, nil)
            }
        }
    }
    
    func getAccountBalance(accountNumber: String, completion: @escaping (Decimal?) -> Void) {
        queue.async {
            guard SecurityManager.shared.checkIntegrity() else {
                DispatchQueue.main.async {
                    completion(nil)
                }
                return
            }
            
            guard let account = self.secureStorage.loadAccount(accountNumber: accountNumber) else {
                DispatchQueue.main.async {
                    completion(nil)
                }
                return
            }
            
            DispatchQueue.main.async {
                completion(account.balance)
            }
        }
    }
    
    func getTransactionHistory(accountNumber: String, completion: @escaping ([Transaction]?) -> Void) {
        queue.async {
            guard SecurityManager.shared.checkIntegrity() else {
                DispatchQueue.main.async {
                    completion(nil)
                }
                return
            }
            
            guard let account = self.secureStorage.loadAccount(accountNumber: accountNumber) else {
                DispatchQueue.main.async {
                    completion(nil)
                }
                return
            }
            
            DispatchQueue.main.async {
                completion(account.transactions)
            }
        }
    }
}

class AccountViewController: UIViewController {
    private let accountNumberLabel = UILabel()
    private let balanceLabel = UILabel()
    private let transactionTableView = UITableView()
    private let transferButton = UIButton(type: .system)
    
    private var accountNumber: String
    private var transactions: [Transaction] = []
    
    init(accountNumber: String) {
        self.accountNumber = accountNumber
        super.init(nibName: nil, bundle: nil)
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        checkSecurityAndLoadData()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        
        accountNumberLabel.translatesAutoresizingMaskIntoConstraints = false
        accountNumberLabel.font = .systemFont(ofSize: 16, weight: .medium)
        accountNumberLabel.textColor = .secondaryLabel
        view.addSubview(accountNumberLabel)
        
        balanceLabel.translatesAutoresizingMaskIntoConstraints = false
        balanceLabel.font = .systemFont(ofSize: 36, weight: .bold)
        balanceLabel.textColor = .label
        view.addSubview(balanceLabel)
        
        transferButton.translatesAutoresizingMaskIntoConstraints = false
        transferButton.setTitle("Transfer Money", for: .normal)
        transferButton.backgroundColor = .systemBlue
        transferButton.setTitleColor(.white, for: .normal)
        transferButton.layer.cornerRadius = 8
        transferButton.addTarget(self, action: #selector(transferButtonTapped), for: .touchUpInside)
        view.addSubview(transferButton)
        
        transactionTableView.translatesAutoresizingMaskIntoConstraints = false
        transactionTableView.delegate = self
        transactionTableView.dataSource = self
        transactionTableView.register(TransactionCell.self, forCellReuseIdentifier: "TransactionCell")
        view.addSubview(transactionTableView)
        
        NSLayoutConstraint.activate([
            accountNumberLabel.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 20),
            accountNumberLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            
            balanceLabel.topAnchor.constraint(equalTo: accountNumberLabel.bottomAnchor, constant: 8),
            balanceLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            
            transferButton.topAnchor.constraint(equalTo: balanceLabel.bottomAnchor, constant: 20),
            transferButton.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            transferButton.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            transferButton.heightAnchor.constraint(equalToConstant: 50),
            
            transactionTableView.topAnchor.constraint(equalTo: transferButton.bottomAnchor, constant: 20),
            transactionTableView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            transactionTableView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            transactionTableView.bottomAnchor.constraint(equalTo: view.bottomAnchor)
        ])
    }
    
    private func checkSecurityAndLoadData() {
        if !SecurityManager.shared.checkIntegrity() {
            showSecurityAlert()
            return
        }
        
        SecurityManager.shared.authenticateUser { [weak self] success, error in
            guard let self = self else { return }
            
            if success {
                self.loadAccountData()
            } else {
                self.showAuthenticationError(error)
            }
        }
    }
    
    private func loadAccountData() {
        accountNumberLabel.text = "Account: \(accountNumber)"
        
        TransactionProcessor.shared.getAccountBalance(accountNumber: accountNumber) { [weak self] balance in
            guard let self = self, let balance = balance else { return }
            self.balanceLabel.text = "$\(balance)"
        }
        
        TransactionProcessor.shared.getTransactionHistory(accountNumber: accountNumber) { [weak self] transactions in
            guard let self = self, let transactions = transactions else { return }
            self.transactions = transactions.sorted { $0.timestamp > $1.timestamp }
            self.transactionTableView.reloadData()
        }
    }
    
    private func showSecurityAlert() {
        let alert = UIAlertController(
            title: "Security Warning",
            message: "This device has failed security checks. The app cannot run on compromised devices.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "Exit", style: .destructive) { _ in
            exit(0)
        })
        present(alert, animated: true)
    }
    
    private func showAuthenticationError(_ error: Error?) {
        let alert = UIAlertController(
            title: "Authentication Failed",
            message: error?.localizedDescription ?? "Unable to authenticate",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "Retry", style: .default) { [weak self] _ in
            self?.checkSecurityAndLoadData()
        })
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        present(alert, animated: true)
    }
    
    @objc private func transferButtonTapped() {
        let alert = UIAlertController(title: "Transfer Money", message: nil, preferredStyle: .alert)
        
        alert.addTextField { textField in
            textField.placeholder = "Destination Account"
            textField.keyboardType = .numberPad
        }
        
        alert.addTextField { textField in
            textField.placeholder = "Amount"
            textField.keyboardType = .decimalPad
        }
        
        alert.addAction(UIAlertAction(title: "Transfer", style: .default) { [weak self] _ in
            guard let self = self,
                  let toAccount = alert.textFields?[0].text,
                  let amountString = alert.textFields?[1].text,
                  let amount = Decimal(string: amountString) else { return }
            
            self.performTransfer(toAccount: toAccount, amount: amount)
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        present(alert, animated: true)
    }
    
    private func performTransfer(toAccount: String, amount: Decimal) {
        let transaction = Transaction(
            id: UUID().uuidString,
            amount: amount,
            type: .transfer,
            timestamp: Date(),
            description: "Transfer to \(toAccount)",
            fromAccount: accountNumber,
            toAccount: toAccount
        )
        
        TransactionProcessor.shared.processTransaction(transaction: transaction) { [weak self] success, error in
            guard let self = self else { return }
            
            if success {
                self.loadAccountData()
                self.showSuccessAlert()
            } else {
                self.showErrorAlert(message: error ?? "Transaction failed")
            }
        }
    }
    
    private func showSuccessAlert() {
        let alert = UIAlertController(title: "Success", message: "Transaction completed successfully", preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
    
    private func showErrorAlert(message: String) {
        let alert = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

extension AccountViewController: UITableViewDelegate, UITableViewDataSource {
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return transactions.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "TransactionCell", for: indexPath) as! TransactionCell
        let transaction = transactions[indexPath.row]
        cell.configure(with: transaction)
        return cell
    }
}

class TransactionCell: UITableViewCell {
    private let descriptionLabel = UILabel()
    private let amountLabel = UILabel()
    private let dateLabel = UILabel()
    
    override init(style: UITableViewCell.CellStyle, reuseIdentifier: String?) {
        super.init(style: style, reuseIdentifier: reuseIdentifier)
        setupUI()
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    private func setupUI() {
        descriptionLabel.translatesAutoresizingMaskIntoConstraints = false
        descriptionLabel.font = .systemFont(ofSize: 16, weight: .medium)
        contentView.addSubview(descriptionLabel)
        
        amountLabel.translatesAutoresizingMaskIntoConstraints = false
        amountLabel.font = .systemFont(ofSize: 16, weight: .bold)
        contentView.addSubview(amountLabel)
        
        dateLabel.translatesAutoresizingMaskIntoConstraints = false
        dateLabel.font = .systemFont(ofSize: 12)
        dateLabel.textColor = .secondaryLabel
        contentView.addSubview(dateLabel)
        
        NSLayoutConstraint.activate([
            descriptionLabel.topAnchor.constraint(equalTo: contentView.topAnchor, constant: 12),
            descriptionLabel.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 16),
            
            amountLabel.centerYAnchor.constraint(equalTo: descriptionLabel.centerYAnchor),
            amountLabel.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -16),
            
            dateLabel.topAnchor.constraint(equalTo: descriptionLabel.bottomAnchor, constant: 4),
            dateLabel.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 16),
            dateLabel.bottomAnchor.constraint(equalTo: contentView.bottomAnchor, constant: -12)
        ])
    }
    
    func configure(with transaction: Transaction) {
        descriptionLabel.text = transaction.description
        
        let sign = transaction.type == .credit ? "+" : "-"
        amountLabel.text = "\(sign)$\(transaction.amount)"
        amountLabel.textColor = transaction.type == .credit ? .systemGreen : .systemRed
        
        let formatter = DateFormatter()
        formatter.dateStyle = .medium
        formatter.timeStyle = .short
        dateLabel.text = formatter.string(from: transaction.timestamp)
    }
}